B.Jy=new A.b_("dsl_halt_accept_y","Halt on y",'Build an FA over the lowercase English alphabet that stops computing and accepts the moment it sees the letter "y".\nUse <<Ha>> to mark a halt-and-accept state, and .-y to mean "every letter except y".',"      n0 = A\n      n1 = <<Ha>>\n      n0 = (484.0, 492.0)\n      Ha = (834.0, 492.0)\n      n0 to Ha = y\n      n0 to n0 = a,b,c,d,e,f,g,h,i,j,k,l,m,n,o,p,q,r,s,t,u,v,w,x,z\n      a,b,c,d,e,f,g,h,i,j,k,l,m,n,o,p,q,r,s,t,u,v,w,x,z loop angle = -1.5708\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.O,B.TN,0.65,"nfa")
B.TQ=new A.cr("dsl_caterpillar_nfa")
B.JR=new A.b_("dsl_caterpillar_dfa","Hungry Caterpillar (DFA)",'The Very Hungry Caterpillar ends by eating EXACTLY one "Green Leaf".\nBuild the deterministic version. Use "." for "all words" and .-"Green Leaf" for "all words except Green Leaf". After seeing a Green Leaf, any further input must go to a dead state.','      n0 = A\n      n1 = B\n      n2 = C\n      n0 = (484.0, 492.0)\n      n1 = (834.0, 492.0)\n      n2 = (1120.0, 486.7)\n      n1 is accepted\n      n2 to n2 = .\n      n1 to n2 = .\n      n0 to n1 = "Green Leaf"\n      n0 to n0 = .-"Green Leaf"\n      l0(.) loop angle = -1.5708\n      .-"Green Leaf" loop angle = -1.5708\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ',B.O,B.TQ,0.83,"dfa")
