B.K_=new A.b_("dsl_len_div3","Length div by 3","Build a DFA over {a, b} that accepts all strings whose length is divisible by 3 (including the empty string).","      n0 = 0\n      n1 = 1\n      n2 = 2\n      n0 = (500.0, 260.0)\n      n1 = (880.0, 440.0)\n      n2 = (500.0, 620.0)\n      n0 is accepted\n      n0 to n1 = a,b\n      n1 to n2 = a,b\n      n2 to n0 = a,b\n      l0(a,b) curve = 60.0\n      l1(a,b) curve = 60.0\n      l2(a,b) curve = 60.0\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.O,B.B_,0.46,"dfa")
B.K8=new A.b_("dsl_at_least_two_b","At Least Two b's",'Build a DFA over {a, b} that accepts all strings containing at least two occurrences of "b".',"      n0 = zero\n      n1 = one\n      n2 = two\n      n0 = (380.0, 380.0)\n      n1 = (740.0, 380.0)\n      n2 = (1100.0, 380.0)\n      n2 is accepted\n      n0 to n1 = b\n      n1 to n2 = b\n      n0 to n0 = a\n      n1 to n1 = a\n      n2 to n2 = a,b\n      l0(a) loop angle = -1.5708\n      l2(a) loop angle = -1.5708\n      l4(a,b) loop angle = -1.5708\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.O,B.B_,0.62,"dfa")
B.Jr=new A.b_("dsl_not_aba",'Does NOT contain "aba"','Build a DFA over {a, b} that accepts strings that do NOT contain "aba" as a substring.',"      n0 = A\n      n1 = B\n      n2 = C\n      n3 = dead\n      n0 = (300.0, 340.0)\n      n1 = (620.0, 340.0)\n      n2 = (940.0, 340.0)\n      n3 = (620.0, 600.0)\n      n0 is accepted\n      n1 is accepted\n      n2 is accepted\n      n0 to n1 = a\n      n0 to n0 = b\n      n1 to n1 = a\n      n1 to n2 = b\n      n2 to n3 = a\n      n2 to n0 = b\n      n3 to n3 = a,b\n      l0(b) loop angle = -1.5708\n      l2(a) loop angle = -1.5708\n      l6(a,b) loop angle = -1.5708\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.O,B.B0,0.8,"dfa")
