B.JG=new A.b_("dsl_binary_mod7","Binary Mod 7","Build a DFA over {0,1} that accepts binary strings whose value is divisible by 7 (binary mod 7 = 0). States 0\u20136 represent the current remainder.","      n0 = 0\n      n1 = 1\n      n2 = 2\n      n3 = 3\n      n4 = 4\n      n5 = 5\n      n6 = 6\n      n0 = (640.0, 92.6)\n      n1 = (1112.0, 196.0)\n      n2 = (1560.0, 282.7)\n      n3 = (250.0, 223.3)\n      n4 = (929.3, 422.7)\n      n5 = (645.3, 592.7)\n      n6 = (303.3, 518.7)\n      n0 is accepted\n      n0 to n1 = 1\n      n0 to n0 = 0\n      n1 to n2 = 0\n      n1 to n3 = 1\n      n3 to n6 = 0\n      n3 to n0 = 1\n      n2 to n5 = 1\n      n2 to n4 = 0\n      n4 to n1 = 0\n      n4 to n2 = 1\n      n5 to n3 = 1\n      n5 to n4 = 1\n      n6 to n5 = 0\n      n6 to n6 = 1\n      l3(1) curve = 21.0\n      l4(0) curve = -194.4\n      l5(1) curve = 34.0\n      l6(1) curve = 316.5\n      l7(0) curve = 152.5\n      l8(0) curve = 17.9\n      l9(1) curve = -15.5\n      l10(1) curve = 15.0\n      l11(1) curve = -59.2\n      l1(0) loop angle = -1.5708\n      l13(1) loop angle = -1.5708\n      to n0\n      to n0 length = 150.3\n      to n0 angle = -0.8423, -0.5390\n    ",B.O,B.TO,0.06,"boss")
